/// The configuration for hyperparameter tuning resources for use in training
/// jobs launched by the tuning job. These resources include compute instances
/// and storage volumes. Specify one or more compute instance configurations and
/// allocation strategies to select resources (optional).
///
/// @nodoc
class HyperParameterTuningInstanceConfig {
  /// The number of instances of the type specified by <code>InstanceType</code>.
  /// Choose an instance count larger than 1 for distributed training algorithms.
  /// See <a
  /// href="https://docs.aws.amazon.com/sagemaker/latest/dg/data-parallel-use-api.html">Step
  /// 2: Launch a SageMaker Distributed Training Job Using the SageMaker Python
  /// SDK</a> for more information.
  final int instanceCount;

  /// The instance type used for processing of hyperparameter optimization jobs.
  /// Choose from general purpose (no GPUs) instance types: ml.m5.xlarge,
  /// ml.m5.2xlarge, and ml.m5.4xlarge or compute optimized (no GPUs) instance
  /// types: ml.c5.xlarge and ml.c5.2xlarge. For more information about instance
  /// types, see <a
  /// href="https://docs.aws.amazon.com/sagemaker/latest/dg/notebooks-available-instance-types.html">instance
  /// type descriptions</a>.
  final TrainingInstanceType instanceType;

  /// The volume size in GB of the data to be processed for hyperparameter
  /// optimization (optional).
  final int volumeSizeInGB;

  HyperParameterTuningInstanceConfig({
    required this.instanceCount,
    required this.instanceType,
    required this.volumeSizeInGB,
  });

  factory HyperParameterTuningInstanceConfig.fromJson(
      Map<String, dynamic> json) {
    return HyperParameterTuningInstanceConfig(
      instanceCount: (json['InstanceCount'] as int?) ?? 0,
      instanceType: TrainingInstanceType.fromString(
          (json['InstanceType'] as String?) ?? ''),
      volumeSizeInGB: (json['VolumeSizeInGB'] as int?) ?? 0,
    );
  }

  Map<String, dynamic> toJson() {
    final instanceCount = this.instanceCount;
    final instanceType = this.instanceType;
    final volumeSizeInGB = this.volumeSizeInGB;
    return {
      'InstanceCount': instanceCount,
      'InstanceType': instanceType.value,
      'VolumeSizeInGB': volumeSizeInGB,
    };
  }
}

/// Configuration for how instances are placed and allocated within
/// UltraServers. This is only applicable for UltraServer capacity.
///
/// @nodoc
class InstancePlacementConfig {
  /// If set to true, allows multiple jobs to share the same UltraServer
  /// instances. If set to false, ensures this job's instances are placed on an
  /// UltraServer exclusively, with no other jobs sharing the same UltraServer.
  /// Default is false.
  final bool? enableMultipleJobs;

  /// A list of specifications for how instances should be placed on specific
  /// UltraServers. Maximum of 10 items is supported.
  final List<PlacementSpecification>? placementSpecifications;

  InstancePlacementConfig({
    this.enableMultipleJobs,
    this.placementSpecifications,
  });

  factory InstancePlacementConfig.fromJson(Map<String, dynamic> json) {
    return InstancePlacementConfig(
      enableMultipleJobs: json['EnableMultipleJobs'] as bool?,
      placementSpecifications: (json['PlacementSpecifications'] as List?)
          ?.nonNulls
          .map(
              (e) => PlacementSpecification.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  Map<String, dynamic> toJson() {
    final enableMultipleJobs = this.enableMultipleJobs;
    final placementSpecifications = this.placementSpecifications;
    return {
      if (enableMultipleJobs != null) 'EnableMultipleJobs': enableMultipleJobs,
      if (placementSpecifications != null)
        'PlacementSpecifications': placementSpecifications,
    };
  }
}

/// Specifies how instances should be placed on a specific UltraServer.
///
/// @nodoc
class PlacementSpecification {
  /// The number of ML compute instances required to be placed together on the
  /// same UltraServer. Minimum value of 1.
  final int instanceCount;

  /// The unique identifier of the UltraServer where instances should be placed.
  final String? ultraServerId;

  PlacementSpecification({
    required this.instanceCount,
    this.ultraServerId,
  });

  factory PlacementSpecification.fromJson(Map<String, dynamic> json) {
    return PlacementSpecification(
      instanceCount: (json['InstanceCount'] as int?) ?? 0,
      ultraServerId: json['UltraServerId'] as String?,
    );
  }

  Map<String, dynamic> toJson() {
    final instanceCount = this.instanceCount;
    final ultraServerId = this.ultraServerId;
    return {
      'InstanceCount': instanceCount,
      if (ultraServerId != null) 'UltraServerId': ultraServerId,
    };
  }
}

