  static ClusterCapacityType fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => ClusterCapacityType._(value));

  @override
  bool operator ==(other) =>
      other is ClusterCapacityType && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

