/// An optimization recommendation generated by an AI recommendation job.
///
/// @nodoc
class AIRecommendation {
  /// The Amazon Resource Name (ARN) of the benchmark job associated with this
  /// recommendation.
  final String? aIBenchmarkJobArn;

  /// The deployment configuration for this recommendation, including the
  /// container image, instance type, instance count, and environment variables.
  final AIRecommendationDeploymentConfiguration? deploymentConfiguration;

  /// The expected performance metrics for this recommendation.
  final List<AIRecommendationPerformanceMetric>? expectedPerformance;

  /// Details about the model package associated with this recommendation.
  final AIRecommendationModelDetails? modelDetails;

  /// The optimization techniques applied in this recommendation.
  final List<AIRecommendationOptimizationDetail>? optimizationDetails;

  /// A description of the recommendation.
  final String? recommendationDescription;

  AIRecommendation({
    this.aIBenchmarkJobArn,
    this.deploymentConfiguration,
    this.expectedPerformance,
    this.modelDetails,
    this.optimizationDetails,
    this.recommendationDescription,
  });

  factory AIRecommendation.fromJson(Map<String, dynamic> json) {
    return AIRecommendation(
      aIBenchmarkJobArn: json['AIBenchmarkJobArn'] as String?,
      deploymentConfiguration: json['DeploymentConfiguration'] != null
          ? AIRecommendationDeploymentConfiguration.fromJson(
              json['DeploymentConfiguration'] as Map<String, dynamic>)
          : null,
      expectedPerformance: (json['ExpectedPerformance'] as List?)
          ?.nonNulls
          .map((e) => AIRecommendationPerformanceMetric.fromJson(
              e as Map<String, dynamic>))
          .toList(),
      modelDetails: json['ModelDetails'] != null
          ? AIRecommendationModelDetails.fromJson(
              json['ModelDetails'] as Map<String, dynamic>)
          : null,
      optimizationDetails: (json['OptimizationDetails'] as List?)
          ?.nonNulls
          .map((e) => AIRecommendationOptimizationDetail.fromJson(
              e as Map<String, dynamic>))
          .toList(),
      recommendationDescription: json['RecommendationDescription'] as String?,
    );
  }

  Map<String, dynamic> toJson() {
    final aIBenchmarkJobArn = this.aIBenchmarkJobArn;
    final deploymentConfiguration = this.deploymentConfiguration;
    final expectedPerformance = this.expectedPerformance;
    final modelDetails = this.modelDetails;
    final optimizationDetails = this.optimizationDetails;
    final recommendationDescription = this.recommendationDescription;
    return {
      if (aIBenchmarkJobArn != null) 'AIBenchmarkJobArn': aIBenchmarkJobArn,
      if (deploymentConfiguration != null)
        'DeploymentConfiguration': deploymentConfiguration,
      if (expectedPerformance != null)
        'ExpectedPerformance': expectedPerformance,
      if (modelDetails != null) 'ModelDetails': modelDetails,
      if (optimizationDetails != null)
        'OptimizationDetails': optimizationDetails,
      if (recommendationDescription != null)
        'RecommendationDescription': recommendationDescription,
    };
  }
}

